 'C:\Program Files (x86)\ATOL\Drivers10\KKT\logs',
 'C:\Users\User\AppData\Roaming\ATOL\drivers10\logs',
 'C:\Users\*\AppData\Roaming\ATOL\drivers10\logs'
)
foreach ($p in $logPaths) {
  if (Test-Path $p) {
    Write-Output "LOG DIR: $p"
    Get-ChildItem $p -Filter *.log -ErrorAction SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 3 FullName, LastWriteTime, Length
  }
}
Get-ChildItem 'C:\Users' -Directory -ErrorAction SilentlyContinue | ForEach-Object {
  $lp = Join-Path $_.FullName 'AppData\Roaming\ATOL\drivers10\logs'
  if (Test-Path $lp) {
    Write-Output "LOG DIR: $lp"
    Get-ChildItem $lp -Filter *.log -ErrorAction SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 2 FullName, LastWriteTime, Length
  }
}
}

