$sec = ConvertTo-SecureString "usr1cv8" -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential(".\usr1cv8", $sec)
Invoke-Command -ComputerName 26.79.213.133 -Credential $cred -ScriptBlock {
$base = 'C:\Users\1\AppData\Roaming\moysklad-kassa'
foreach ($f in @('retail_e87bd531-abc8-11ee-0a80-07a9004c1980.sqlite','retail_e87bd531-abc8-11ee-0a80-07a9004c1980.sqlite-wal')) {
  $path = Join-Path $base $f
  if (Test-Path $path) {
    $tmp = "C:\Users\1\AppData\Local\Temp\$f"
    Copy-Item $path $tmp -Force
    $bytes=[IO.File]::ReadAllBytes($tmp)
    $ascii=[Text.Encoding]::ASCII.GetString($bytes)
    $jwts = [regex]::Matches($ascii,'eyJ[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}')
    if ($jwts.Count -gt 0) { Write-Output "JWT in $f : $($jwts[0].Value.Substring(0,40))..." }
  }
}
# copy leveldb ldb
$ldbDir = 'C:\Users\1\AppData\Roaming\moysklad-kassa\Local Storage\leveldb'
$tmpDir = 'C:\Users\1\AppData\Local\Temp\leveldb_copy'
if (Test-Path $tmpDir) { Remove-Item $tmpDir -Recurse -Force }
New-Item $tmpDir -ItemType Directory | Out-Null
Get-ChildItem $ldbDir -Filter *.ldb -EA SilentlyContinue | ForEach-Object { Copy-Item $_.FullName (Join-Path $tmpDir $_.Name) -Force }
Get-ChildItem $tmpDir -Filter *.ldb | ForEach-Object {
  $ascii=[Text.Encoding]::ASCII.GetString([IO.File]::ReadAllBytes($_.FullName))
  $jwts=[regex]::Matches($ascii,'eyJ[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}')
  foreach ($j in $jwts) { Write-Output "JWT from $($_.Name): $($j.Value.Substring(0,[Math]::Min(60,$j.Value.Length)))..." }
  if ($ascii -match 'authToken.{0,5}([A-Za-z0-9._-]{30,})') { Write-Output "authToken raw found" }
}
}

