$py = "$env:TEMP\pyembed\python.exe"
$script = @'
import base64, re, pathlib
root = pathlib.Path(r'C:\Users\cherkasov.n\Desktop\OpenVPN-конфиги Port-Mol')
files = list(root.rglob('*'))

def pem_blocks(text, kind):
    pat = rf'-----BEGIN {kind}-----\s*(.*?)\s*-----END {kind}-----'
    return [base64.b64decode(re.sub(r'\s+', '', m)) for m in re.findall(pat, text, re.S)]

def rd_len(b, i):
    n=b[i]; i+=1
    if n<128: return n,i
    k=n&127; return int.from_bytes(b[i:i+k],'big'), i+k

def rd_tlv(b,i):
    tag=b[i]; l,j=rd_len(b,i+1); return tag,b[j:j+l],j+l

def children(seq):
    out=[]; i=0
    while i<len(seq):
        tag,val,i=rd_tlv(seq,i); out.append((tag,val))
    return out

def der_int(v):
    return int.from_bytes(v, 'big')

def rsa_pub_mod_from_cert(der):
    t,cert,_=rd_tlv(der,0); assert t==0x30
    tbs=children(cert)[0][1]
    ch=children(tbs)
    i=0
    if ch[0][0] == 0xA0: i=1
    # version(optional), serial, sig, issuer, validity, subject, spki
    spki=ch[i+5][1]
    spki_ch=children(spki)
    bit=spki_ch[1][1]
    pub_der=bit[1:]
    t,pub,_=rd_tlv(pub_der,0); assert t==0x30
    return der_int(children(pub)[0][1])

def rsa_priv_mod_from_key(der):
    t,seq,_=rd_tlv(der,0); assert t==0x30
    ch=children(seq)
    # PKCS#8: version, alg, privateKey OCTET STRING
    if len(ch)>=3 and ch[1][0]==0x30 and ch[2][0]==0x04:
        t,inner,_=rd_tlv(ch[2][1],0); assert t==0x30
        return der_int(children(inner)[1][1])
    # PKCS#1: version, n, e...
    return der_int(ch[1][1])

certs=[]; keys=[]
for p in files:
    if p.is_file() and p.suffix.lower() in ('.ovpn','.crt','.key'):
        try: txt=p.read_text(encoding='utf-8', errors='ignore')
        except Exception: continue
        for i,der in enumerate(pem_blocks(txt,'CERTIFICATE')):
            try: certs.append((str(p), i, rsa_pub_mod_from_cert(der)))
            except Exception as e: pass
        for i,der in enumerate(pem_blocks(txt,'PRIVATE KEY')+pem_blocks(txt,'RSA PRIVATE KEY')):
            try: keys.append((str(p), i, rsa_priv_mod_from_key(der)))
            except Exception as e: print('KEY_PARSE_FAIL', p, e)

print('MATCHES:')
for cp,ci,cm in certs:
    for kp,ki,km in keys:
        if cm==km:
            print(f'CERT[{ci}] {cp}  <==>  KEY[{ki}] {kp}')
print('\nOVPN INTERNAL:')
for p in files:
    if p.is_file() and p.suffix.lower()=='.ovpn':
        txt=p.read_text(encoding='utf-8', errors='ignore')
        cs=[]; ks=[]
        for der in pem_blocks(txt,'CERTIFICATE'):
            try: cs.append(rsa_pub_mod_from_cert(der))
            except: pass
        for der in pem_blocks(txt,'PRIVATE KEY')+pem_blocks(txt,'RSA PRIVATE KEY'):
            try: ks.append(rsa_priv_mod_from_key(der))
            except: pass
        if cs or ks:
            # usually client cert is last cert after CA; any cert matching key is ok
            ok=bool(ks and any(c==ks[0] for c in cs))
            print(('OK   ' if ok else 'BAD  ')+str(p), 'certs=',len(cs),'keys=',len(ks))
'@
