# Install AmneziaWG tunnel service on MARK1 (headless, no GUI)
param(
    [string]$RemoteIP = '192.168.2.148',
    [string]$RemoteUser = 'usr1cv8',
    [string]$RemotePassword = 'usr1cv8',
    [string]$ConfName = 'mark1-markt'
)

$ErrorActionPreference = 'Stop'
$msiLocal = Join-Path $PSScriptRoot 'amneziawg-amd64-2.0.1.msi'
$msiUrl = 'https://github.com/amnezia-vpn/amneziawg-windows-client/releases/download/2.0.1/amneziawg-amd64-2.0.1.msi'
$confLocal = Join-Path $PSScriptRoot "$ConfName.conf"

if (-not (Test-Path $msiLocal)) {
    Write-Host "Downloading AmneziaWG MSI..."
    Invoke-WebRequest -Uri $msiUrl -OutFile $msiLocal
}

if (-not (Test-Path $confLocal)) {
    throw "Config not found: $confLocal"
}

$sec = ConvertTo-SecureString $RemotePassword -AsPlainText -Force
$cred = New-Object PSCredential (".\$RemoteUser", $sec)
$s = New-PSSession -ComputerName $RemoteIP -Credential $cred

$remoteDir = 'C:\ProgramData\AmneziaVPN'
Copy-Item -ToSession $s -Path $msiLocal -Destination "$remoteDir\amneziawg-amd64-2.0.1.msi" -Force
Copy-Item -ToSession $s -Path $confLocal -Destination "$remoteDir\$ConfName.conf" -Force

$result = Invoke-Command -Session $s -ScriptBlock {
    param($remoteDir, $confName)

    $log = Join-Path $remoteDir 'awg-install.log'
    function Log($m) { Add-Content $log "$(Get-Date -Format o) $m" }
    Remove-Item $log -ErrorAction SilentlyContinue

    $msi = Join-Path $remoteDir 'amneziawg-amd64-2.0.1.msi'
    $conf = Join-Path $remoteDir "$confName.conf"
    $awgExe = 'C:\Program Files\AmneziaWG\amneziawg.exe'

    Log 'install msi'
    $p = Start-Process msiexec.exe -ArgumentList "/i `"$msi`" /qn DO_NOT_LAUNCH=1" -Wait -PassThru
    Log "msi exit=$($p.ExitCode)"
    if ($p.ExitCode -ne 0 -and $p.ExitCode -ne 3010) { throw "MSI failed: $($p.ExitCode)" }

    if (-not (Test-Path $awgExe)) {
        $found = Get-ChildItem 'C:\Program Files' -Filter 'amneziawg.exe' -Recurse -ErrorAction SilentlyContinue | Select-Object -First 1
        if ($found) { $awgExe = $found.FullName }
    }
    Log "awg=$awgExe exists=$(Test-Path $awgExe)"

    # remove old tunnel if any
    & $awgExe /uninstalltunnelservice $confName 2>&1 | ForEach-Object { Log "uninstall: $_" }

    Log 'install tunnel service'
    $out = & $awgExe /installtunnelservice $conf 2>&1
    $out | ForEach-Object { Log "install: $_" }

    $svcName = "AmneziaWGTunnel`$$confName"
    Start-Sleep 2
    $svc = Get-Service -Name $svcName -ErrorAction SilentlyContinue
    if ($svc) {
        if ($svc.Status -ne 'Running') { Start-Service $svcName -ErrorAction SilentlyContinue }
        Start-Sleep 5
        $svc.Refresh()
        Log "service status=$($svc.Status)"
    } else {
        Log 'service not found, list awg services'
        Get-Service | Where-Object { $_.Name -like 'AmneziaWG*' } | ForEach-Object { Log "svc $($_.Name) $($_.Status)" }
    }

    Start-Sleep 10
    $wg = Get-NetAdapter -ErrorAction SilentlyContinue | Where-Object {
        $_.InterfaceDescription -match 'WireGuard|Amnezia|Wintun|Mullvad'
    }
    if ($wg) { Log "adapter $($wg.Name) $($wg.Status) $($wg.InterfaceDescription)" }

    Get-NetIPAddress -AddressFamily IPv4 -ErrorAction SilentlyContinue |
        Where-Object { $_.IPAddress -notlike '127.*' -and $_.IPAddress -notlike '169.254.*' } |
        ForEach-Object { Log "ip $($_.InterfaceAlias) $($_.IPAddress)" }

    $ping = Test-Connection 8.8.8.8 -Count 1 -Quiet -ErrorAction SilentlyContinue
    Log "ping8.8.8.8=$ping"
    Log 'END'

    @{
        log = Get-Content $log -Raw
        adapters = Get-NetAdapter -ErrorAction SilentlyContinue | Select-Object Name, Status, InterfaceDescription
        ips = Get-NetIPAddress -AddressFamily IPv4 -ErrorAction SilentlyContinue |
            Where-Object { $_.IPAddress -notlike '127.*' } |
            Select-Object InterfaceAlias, IPAddress
        services = Get-Service | Where-Object { $_.Name -like 'AmneziaWG*' } | Select-Object Name, Status
    }
} -ArgumentList $remoteDir, $ConfName

