# Full restore: fix network, disable broken AWG tunnel, prep Amnezia for cherkasov.n
param(
    [string]$RemoteIP = '192.168.2.148',
    [string]$RemoteUser = 'usr1cv8',
    [string]$RemotePassword = 'usr1cv8'
)

$sec = ConvertTo-SecureString $RemotePassword -AsPlainText -Force
$cred = New-Object PSCredential (".\$RemoteUser", $sec)

$targets = @($RemoteIP, '26.243.230.163')
$session = $null
foreach ($t in $targets) {
    try {
        $session = New-PSSession -ComputerName $t -Credential $cred -ErrorAction Stop
        Write-Host "Connected via $t"
        break
    } catch { Write-Host "No connect $t" }
}
if (-not $session) { throw 'MARK1 unreachable on LAN and Radmin IP' }

Invoke-Command -Session $session -ScriptBlock {
    $log = 'C:\ProgramData\AmneziaVPN\restore.log'
    function Log($m) { Add-Content $log "$(Get-Date -Format o) $m" }
    Remove-Item $log -ErrorAction SilentlyContinue
    Log 'restore start'

    Get-Service -EA SilentlyContinue | Where-Object { $_.Name -like 'AmneziaWG*' } | ForEach-Object {
        Log "stop/disable $($_.Name)"
        Stop-Service $_.Name -Force -EA SilentlyContinue
        Set-Service $_.Name -StartupType Disabled -EA SilentlyContinue
    }

    $awg = 'C:\Program Files\AmneziaWG\amneziawg.exe'
    if (Test-Path $awg) { & $awg /uninstalltunnelservice mark1-markt 2>&1 | ForEach-Object { Log $_ } }

    Get-NetRoute -DestinationPrefix '0.0.0.0/0' -EA SilentlyContinue |
        Where-Object { $_.InterfaceAlias -match 'Radmin|WireGuard|Amnezia|Wintun' } |
        ForEach-Object { Remove-NetRoute -InputObject $_ -Confirm:$false -EA SilentlyContinue; Log "del route $($_.InterfaceAlias)" }

    Enable-NetAdapter -Name 'Ethernet' -Confirm:$false -EA SilentlyContinue

    $gw = '192.168.2.1'
    if (-not (Get-NetRoute -DestinationPrefix '0.0.0.0/0' -InterfaceAlias 'Ethernet' -EA SilentlyContinue)) {
        New-NetRoute -DestinationPrefix '0.0.0.0/0' -InterfaceAlias 'Ethernet' -NextHop $gw -RouteMetric 1 -EA SilentlyContinue | Out-Null
        Log 'default route via Ethernet'
    }

    foreach ($t in @('AmneziaMark1Gui','AmneziaCherkasovConnect')) {
        Unregister-ScheduledTask -TaskName $t -Confirm:$false -EA SilentlyContinue
    }

    $pingLan = Test-Connection $gw -Count 1 -Quiet -EA SilentlyContinue
    $pingExt = Test-Connection 8.8.8.8 -Count 1 -Quiet -EA SilentlyContinue
    Log "ping gw=$pingLan ext=$pingExt END"
    Get-Content $log -Raw
}

Remove-PSSession $session

# SAFE network restore for MARK1 — only if LAN is broken.
# Does NOT install/start VPN tunnels. Does NOT touch Radmin VPN adapter routes unless they hijack 0.0.0.0/0.
param(
    [string]$RemoteIP = '192.168.2.148',
    [string]$RemoteUser = 'usr1cv8',
    [string]$RemotePassword = 'usr1cv8',
    [switch]$WhatIf
)

$sec = ConvertTo-SecureString $RemotePassword -AsPlainText -Force
$cred = New-Object PSCredential (".\$RemoteUser", $sec)

if (-not (Test-NetConnection $RemoteIP -Port 5985 -WarningAction SilentlyContinue).TcpTestSucceeded) {
    throw "WinRM to $RemoteIP unavailable. Run on-site: disable AmneziaWG services, ensure default route via Ethernet."
}

Invoke-Command -ComputerName $RemoteIP -Credential $cred -ScriptBlock {
    param($whatIf)

    $log = 'C:\ProgramData\AmneziaVPN\restore-safe.log'
    function Log($m) { Add-Content $log "$(Get-Date -Format o) $m" }
    Remove-Item $log -ErrorAction SilentlyContinue

    $plan = @()

    $badRoutes = Get-NetRoute -DestinationPrefix '0.0.0.0/0' -ErrorAction SilentlyContinue |
        Where-Object { $_.InterfaceAlias -ne 'Ethernet' }
    foreach ($r in $badRoutes) { $plan += "REMOVE default route via $($r.InterfaceAlias) -> $($r.NextHop)" }

    $awg = Get-Service -ErrorAction SilentlyContinue | Where-Object { $_.Name -like 'AmneziaWG*' -and $_.Status -eq 'Running' }
    foreach ($s in $awg) { $plan += "STOP+DISABLE $($s.Name)" }

    $ethDown = Get-NetAdapter -ErrorAction SilentlyContinue | Where-Object { $_.Name -eq 'Ethernet' -and $_.Status -ne 'Up' }
    if ($ethDown) { $plan += 'ENABLE Ethernet' }

    $hasEthDefault = Get-NetRoute -DestinationPrefix '0.0.0.0/0' -InterfaceAlias 'Ethernet' -ErrorAction SilentlyContinue
    if (-not $hasEthDefault) { $plan += 'ADD default route 0.0.0.0/0 via Ethernet -> 192.168.2.1' }

    Log "plan: $($plan -join ' | ')"
    if ($whatIf) { return @{ whatIf = $true; plan = $plan; log = Get-Content $log -Raw } }

    foreach ($s in $awg) {
        Stop-Service $s.Name -Force -ErrorAction SilentlyContinue
        Set-Service $s.Name -StartupType Disabled -ErrorAction SilentlyContinue
        Log "stopped $($s.Name)"
    }

    foreach ($r in $badRoutes) {
        Remove-NetRoute -InputObject $r -Confirm:$false -ErrorAction SilentlyContinue
        Log "removed route $($r.InterfaceAlias)"
    }

    if ($ethDown) { Enable-NetAdapter -Name 'Ethernet' -Confirm:$false -ErrorAction SilentlyContinue }

    if (-not $hasEthDefault) {
        New-NetRoute -DestinationPrefix '0.0.0.0/0' -InterfaceAlias 'Ethernet' -NextHop '192.168.2.1' -RouteMetric 1 -ErrorAction SilentlyContinue | Out-Null
        Log 'added eth default'
    }

    $pingGw = Test-Connection 192.168.2.1 -Count 1 -Quiet -ErrorAction SilentlyContinue
    $pingExt = Test-Connection 8.8.8.8 -Count 1 -Quiet -ErrorAction SilentlyContinue
    Log "verify gw=$pingGw ext=$pingExt END"

    @{
        plan = $plan
        log = Get-Content $log -Raw
        adapters = Get-NetAdapter -ErrorAction SilentlyContinue | Select-Object Name, Status
        defaultRoute = Get-NetRoute -DestinationPrefix '0.0.0.0/0' -ErrorAction SilentlyContinue |
            Select-Object InterfaceAlias, NextHop
        pingGw = $pingGw
        pingExt = $pingExt
    }
} -ArgumentList $WhatIf.IsPresent

# SAFE Amnezia connect — GUI only, NO route/tunnel/service changes.
# Run ONLY when cherkasov.n is logged in interactively on MARK1.
param(
    [string]$RemoteIP = '192.168.2.148',
    [string]$RemoteUser = 'usr1cv8',
    [string]$RemotePassword = 'usr1cv8',
    [string]$VpnUser = 'cherkasov.n',
    [switch]$WhatIf
)

. "$PSScriptRoot\mark1-check-safe.ps1" -RemoteIP $RemoteIP | Out-Null
if ($LASTEXITCODE -ne 0) { throw 'Pre-check failed — aborting' }

$sec = ConvertTo-SecureString $RemotePassword -AsPlainText -Force
$cred = New-Object PSCredential (".\$RemoteUser", $sec)

$pre = Invoke-Command -ComputerName $RemoteIP -Credential $cred -ScriptBlock {
    param($vpnUser)
    $loggedIn = (query user 2>$null) -match [regex]::Escape($vpnUser)
    @{
        userLoggedIn = [bool]$loggedIn
        sessions = query user 2>$null
        amneziaExists = Test-Path 'C:\Program Files\AmneziaVPN\AmneziaVPN.exe'
        vpnOnDesktop = Test-Path "C:\Users\$vpnUser\Desktop\mark1-amnezia.vpn"
    }
} -ArgumentList $VpnUser

if (-not $pre.userLoggedIn) {
    throw "ABORT: $VpnUser not logged in. Amnezia works only under $VpnUser — log in first, then rerun."
}
if (-not $pre.amneziaExists) {
    throw 'ABORT: AmneziaVPN.exe not found'
}

Write-Host "OK to launch GUI for $VpnUser (no network changes)" -ForegroundColor Green
if ($WhatIf) { $pre | ConvertTo-Json; return }

Invoke-Command -ComputerName $RemoteIP -Credential $cred -ScriptBlock {
    param($vpnUser)
    $exe = 'C:\Program Files\AmneziaVPN\AmneziaVPN.exe'
    $st = (Get-Date).AddMinutes(1).ToString('HH:mm')
    schtasks /Delete /TN 'AmneziaSafeGui' /F 2>$null | Out-Null
    schtasks /Create /TN 'AmneziaSafeGui' /TR "`"$exe`"" /SC ONCE /ST $st /RU $vpnUser /IT /F | Out-Null
    schtasks /Run /TN 'AmneziaSafeGui' | Out-Null
    'Launched Amnezia GUI in interactive session. User must click Connect manually.'
} -ArgumentList $VpnUser

